    public ScheduleHandler(Object httpRequest,Object httpResponse,Map arguments,Object exec){
          this.arguments				= arguments;
          this.httpRequest 				= arguments.get("httpRequest");
          this.httpResponse 			= arguments.get("httpResponse");
          this.exec						= exec;
		  this.pluginContext 			= arguments.get("pluginContext");
      	  this.moduleContext 			= arguments.get("moduleContext"); 

          exec.logger().info("ScheduleHandler");
    }  

    public String process(Map automation,Object aiInterfacePlugin,Object task){
        //task,aiInterfacePlugin
		Map newLeadSource = exec.using(pluginContext.resolveToUserAssetDir("/")).call("/work/BusinessTools/web/secure/sales-lead-management/db-access/get_next_new_lead_source.stm");

        if(newLeadSource == null)
      		exec.logger().info("Agent ${automation.name} is skipping action, no lead sources to extract from.".toString());
      	else
          exec.logger().info("Agent ${automation.name} is extracting from a new lead source (${newLeadSource.website_url}).".toString());

        return newLeadSource == null?"skip":true;
    }
}

return new ScheduleHandler(arguments.get("httpRequest"),arguments.get("httpResponse"),arguments,exec).process(automation,aiInterfacePlugin,task);
